var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"오랜만이야, 승선을 환영하지. 맨션의 마담.","JPN":"久しぶりだな。乗船を歓迎する、マンションのマダム。","ENG":"Long time no see. Welcome aboard, Madam of the Mansion.","TWN":"好久不見，歡迎你，曼森的女主人。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_AIRPLANE"},{"id":"L4_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"됐으니까 선실로 안내나 해. 소금기로 머리가 푸석거리기 전에.","JPN":"いいから船室に案内して。潮風のせいで髪の毛が痛む前に。","ENG":"Shut up and just show me to the cabins. All this salty air is going to dry out my hair.","TWN":"好了，快帶我到船艙吧，我頭髮都沒型了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"꼴불견이군.","JPN":"みっともないな。","ENG":"Ugh, you're ridiculous.","TWN":"真是無語。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그 나이 먹고 아직도 머릿결 타령이나 하는 거냐?","JPN":"その歳でまだ髪の毛なんかを気にしてんのか？","ENG":"You're still raving on about your hair at your age?","TWN":"都一把年紀了，還在意什麼髮型？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"오일 냄새나 맡고 다니던 정비공 주제에 분수도 모르고 나랑 말을 섞으려 드네?","JPN":"オイル臭い整備工のくせに、身の程も知らずに私に話しかけてるの？","ENG":"What does a grease monkey like you know about hair anyway?","TWN":"區區一個臭維修工，不知道分寸，竟敢和我搭話？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"매일 두르고 다니던 그 거지 같은 사막 전투복은 수용소에서 압수라도 당했니?","JPN":"いつものボロボロな砂漠用戦闘服は収容所で押収でもされたのかしら？","ENG":"And what happened to the ragged desert uniform you wore every day? Did they confiscate it at the penitentiary?","TWN":"妳每天穿著那破爛沙漠戰鬥服，是被集中營抓走了嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"하여간 보여줄 것도 없으면서 풀어헤치고 다니는 것부터 품위라곤 찾아볼 수가 없다니까.","JPN":"見せられるモノもないくせに見せっぱなしで、まったく品が感じられないんだから。","ENG":"For someone who likes to show so much skin, you've got nothing much to see, really. Such lack of class.","TWN":"也不知道妳為什麼每天都不把衣服扣上，真是沒品。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐라고?! 기계의 완벽함도 제대로 모르는 년이 뭐가 어째?","JPN":"はあ？　機械の完璧さもろくに知らないバカが何だと？","ENG":"What? What do you know, you dimwit? You don't even appreciate the perfection of machinery!","TWN":"什麼？！妳一個連機器的機都不會寫的臭婆娘還敢亂說？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"꽃이니 메이드니 하는 나약한 살덩이들에 둘러싸여서 기술 발전에도 못 따라오는 퇴물 주제에 허세만 부리긴!","JPN":"花だのメイドだの弱々しい肉体に囲まれて、技術発展にもついて来れない年代物のくせに見栄ばかり張りやがって！","ENG":"You just keep yourself pampered by those weak lumps of flesh you call flowers or maids or whatever!","TWN":"什麼花啊，女僕啊，天天被一群小女子包圍，連個技術都發展不出來的廢物，還敢說大話！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"워, 워. 기껏 수용소에서 꺼내줬더니 만나자마자 싸우면 곤란해, 아가씨들.","JPN":"どうどう。せっかく収容所から出してやったのに、会ってすぐ喧嘩されても困るぞ、お嬢ちゃんたち。","ENG":"Come on now, ladies. I just got you out of jail. I can't have you fighting already.","TWN":"喂，喂，我把妳們從集中營救出來，可不是為了讓妳們吵架，小姐們。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"정 싸우고 싶으면 저기 물에 들어가서 싸우던가.","JPN":"喧嘩したいなら、あの海の中でやってくれ。","ENG":"If you really must fight, you could just jump into the water.","TWN":"如果妳們想吵，不如進水裡打一架吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>평의회</color> 멤버 두 명이 허우적거리면서 싸우는 광경이라니, 관람하는 재미가 쏠쏠하겠군.","JPN":"<color=#ffd34c>評議会</color>メンバー2人がじたばたしながら戦う光景って、観覧する側はさぞかし楽しいだろうな。","ENG":"Watching two members of <color=#ffd34c>the Council</color> catfight while trying to swim should be interesting.","TWN":"看兩個<color=#ffd34c>評議會</color>成員在打架的樣子，想想就覺得有趣。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"누가 싸운대? 시비를 걸어오길래 대답했을 뿐이야.","JPN":"喧嘩？　因縁をつけてきたから答えただけよ。","ENG":"Who said anything about fighting? Besides, she started it.","TWN":"誰吵架了？我只是看有人搬弄是非，便說了一句而已。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"금속의 아름다움을 아는 내가 참도록 하지. 내 기생충들은 물을 싫어하니까.","JPN":"ちっ……ここは金属の美しさを知る俺が我慢してやる。うちの寄生虫は水が嫌いだからな。","ENG":"I'll be the bigger person, as someone who truly appreciates the beauty of metal. My parasites hate water, after all.","TWN":"知道金屬之美的我暫且忍一忍吧，我的寄生蟲可是很討厭水的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"하하. 이것 봐. 사이 좋은 모습이 훨씬 더 보기 좋잖아.","JPN":"ハハハ、ほら。仲良くしたほうがずっといいぞ。","ENG":"Hah hah, see? It's so much better when we all get along.","TWN":"哈哈，妳們這樣可比吵吵鬧鬧好多了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"잔말은 됐어. 평의회는 왜 소집한 거야?","JPN":"無駄話はその辺にしてちょうだい。それで、評議会はどうして召集したの？","ENG":"Enough with the small talk. Why did you convene the Council?","TWN":"廢話少說，但你怎麼突然想起要召開評議會？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"나오는 데 거들어 준 건 고맙지만 이걸 빌미로 괜한 간섭을 하는 건 사절이야.","JPN":"脱出を手伝ってくれたのはありがたいけど、それを口実に余計な干渉をするのはお断りよ。","ENG":"As much as I appreciate you busting me out of there, I'm going to pass if you're going to use that as leverage to intervene in my life.","TWN":"雖然我很感謝你出手相救，但我不希望你以此作為藉口隨意進行干涉。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"의장인 내가 그럴 리가 있나.","JPN":"議長の私がそんなことするわけないだろ。","ENG":"Oh, I couldn't possibly. I'm the chairperson.","TWN":"我作為議長，不會那麼做的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"검은 평의회는 멤버들간의 존중을 가장 중요한 원칙으로 삼고 있다네.","JPN":"黒の評議会はメンバー間の尊重を最も重要な原則としている。","ENG":"The Dark Council considers mutual respect among members as the paramount principle.","TWN":"評議會最重要的原則就是成員之間相互尊重。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그러시겠지. 말이 좋아 평의회지 까놓고 보면 범죄자 소굴이잖아?","JPN":"そうだろうね。評議会と名付けただけで、ぶっちゃけ犯罪者の巣窟だろ？","ENG":"Of course you do. Really, the Council is just a bunch of criminals.","TWN":"說的倒是好聽，什麼評議會，說白了不就是罪犯聚集地。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"남의 말이라곤 지지리도 안 들어먹는 놈들뿐인데 간섭한다고 곱게 받아들일 리 없지.","JPN":"人の話をちっとも聞かない奴らばかりなのに、干渉するからといって素直に受け取るはずない。","ENG":"None of us give a rip about what other people want. We won't take kindly to nosy fools.","TWN":"盡是些絕對不聽他人言的傢伙，怎麼可能任人隨意干涉。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"애초에 오늘 소집 명령에도 나온 녀석들 몇 놈 없을 거 아냐?","JPN":"そもそも今日の招集命令だって無視した奴がほとんどだろ？","ENG":"I bet you didn't get many of us to show up for today's session either.","TWN":"而且今天召開會議，也沒有幾個傢伙出席吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"안타깝지만 그 말대로야.","JPN":"残念ながらそのとおりだ。","ENG":"Unfortunately, you are right.","TWN":"妳說的沒錯。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"이래서야 언더그라운드를 지배하는 우리 평판이 땅에 떨어져도 할 말이 없겠군.","JPN":"これじゃあ、アンダーグラウンドを支配する我々の評判が地に落ちても仕方がないな。","ENG":"At this rate, I wouldn't be surprised of our reputation as the leaders of the underground plummets even further.","TWN":"這樣一來統治地下世界的我們即使名聲掃地也無話可說。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그럼에도 불구하고 내가 소집령을 발동한 이유가 있다네.","JPN":"それにもかかわらず、召集令を発動したには理由がある。","ENG":"But despite all that, I convened this meeting for a reason.","TWN":"儘管如此，我發出召集令是有理由的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"이유?","JPN":"理由？","ENG":"What reason?","TWN":"理由？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그래, 최근 자꾸 눈에 거슬리는 태스크포스 컴퍼니가 하나 있지 않나?","JPN":"そう。ここ最近、とても目障りなタスクフォースカンパニーがあるだろ？","ENG":"Have you noticed how a certain TASKFORCE company has proven to be rather pesky lately?","TWN":"對，最近有個特遣勢力公司很礙眼。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"......코핀 컴퍼니.","JPN":"……コフィンカンパニー。","ENG":"...The Coffin Company.","TWN":"……科芬公司。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"공식적으로 검은 평의회는 관리국과 그 산하 조직에 대해 중립적인 입장을 취하고 있네.","JPN":"公には黒の評議会は管理局とその傘下組織に対して中立的な立場をとっている。","ENG":"Officially, the Dark Council maintains a neutral position with regard to the Administration and its subordinate organizations.","TWN":"正確來說，評議會對管理局和旗下組織抱持著中立的立場。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"하지만 그쪽이 먼저 우리의 영역을 침범한다면 가만히 있을 수도 없지.","JPN":"しかしそっちが先に我々の領域を侵してくるなら、黙ってはいられない。","ENG":"But if they violate our domain first, we can't just sit back and watch.","TWN":"但如果對方先侵犯了我們的領域，我們也不能任人宰割。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"당장은 별 것 아니라고 생각할 수도 있겠지만 이대로 두면 아주 귀찮은 일들이 벌어질 테니까.","JPN":"今は大したことないと思うだろうが、このままにしておくと厄介なことになるだろう。","ENG":"Even if we don't think much of it initially, things could grow out of control if we just leave it be.","TWN":"雖然目前不覺得有什麼，但如果放著不管，以後可就麻煩了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그러니 사이 좋게 둘러앉아서 대책을 논의해 보자고.","JPN":"だから仲良く輪になって対策を話し合ってみようじゃないか。","ENG":"So let's all gather around like good friends and discuss a way forward.","TWN":"所以我們還是好好商量一下對策吧。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"귀찮게 구는 코핀 컴퍼니 녀석들을 어떻게 해야 치워 버릴 수 있을지. \xA0","JPN":"あの鬱陶しいコフィンカンパニーの連中をどうやって片付けるか、についてな。\xA0","ENG":"How will we get those pesky Coffin Company fools out of our hair? \xA0","TWN":"看看接下來怎麼處理科芬公司那些煩人的傢伙們。\xA0"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};